import React, { useContext, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { LogOut, User, Calendar, Home, Menu, X } from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
    setIsMobileMenuOpen(false);
  };

  return (
    <nav className="bg-white/95 backdrop-blur-md border-b border-gray-100 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
        {/* Logo */}
        <Link 
          to="/" 
          className="flex items-center gap-2 text-2xl font-semibold text-gray-900 hover:text-blue-600 transition-colors"
        >
          <div className="w-9 h-9 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-500/30">
            <Home size={22} />
          </div>
          <span>MockInterviews</span>
        </Link>

        {/* Desktop Navigation */}
        <div className="hidden md:flex items-center gap-8">
          {!user ? (
            <div className="flex items-center gap-4">
              <Link 
                to="/login" 
                className="text-gray-600 hover:text-gray-900 font-medium transition-colors"
              >
                Login
              </Link>
              <Link 
                to="/register" 
                className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white px-6 py-2.5 rounded-2xl font-semibold hover:shadow-xl hover:shadow-blue-500/30 transition-all active:scale-95"
              >
                Get Started
              </Link>
            </div>
          ) : (
            <>
              <div className="flex items-center gap-8">
                {/* Role-based Links */}
                {user.role === 'ROLE_INTERVIEWER' && (
                  <Link 
                    to="/interviewer/availability" 
                    className="flex items-center gap-2 text-gray-600 hover:text-blue-600 font-medium transition-colors"
                  >
                    <Calendar size={20} />
                    <span>Availability</span>
                  </Link>
                )}

                {user.role === 'ROLE_CANDIDATE' && (
                  <Link 
                    to="/candidate/search" 
                    className="flex items-center gap-2 text-gray-600 hover:text-blue-600 font-medium transition-colors"
                  >
                    Find Interviewers
                  </Link>
                )}
              </div>

              {/* User Menu */}
              <div className="flex items-center gap-3 pl-6 border-l border-gray-100">
                <div className="flex items-center gap-3 bg-gray-50 rounded-2xl px-4 py-1.5">
                  <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-indigo-500 rounded-xl flex items-center justify-center text-white font-semibold shadow">
                    {user.sub?.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-gray-800">{user.sub}</p>
                    <p className="text-[10px] text-gray-500 -mt-0.5 capitalize">
                      {user.role?.replace('ROLE_', '').toLowerCase()}
                    </p>
                  </div>
                </div>

                <button
                  onClick={handleLogout}
                  className="p-3 hover:bg-red-50 text-red-500 hover:text-red-600 rounded-2xl transition-all hover:scale-105"
                  title="Logout"
                >
                  <LogOut size={20} />
                </button>
              </div>
            </>
          )}
        </div>

        {/* Mobile Menu Button */}
        <button 
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="md:hidden p-2 text-gray-700"
        >
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden border-t bg-white">
          <div className="px-6 py-6 flex flex-col gap-6">
            {!user ? (
              <>
                <Link to="/login" className="text-lg font-medium">Login</Link>
                <Link 
                  to="/register" 
                  className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white py-4 rounded-2xl text-center font-semibold"
                >
                  Get Started
                </Link>
              </>
            ) : (
              <>
                {user.role === 'ROLE_INTERVIEWER' && (
                  <Link to="/interviewer/availability" className="flex items-center gap-3 text-lg">
                    <Calendar size={24} /> Availability
                  </Link>
                )}
                {user.role === 'ROLE_CANDIDATE' && (
                  <Link to="/candidate/search" className="text-lg">
                    Find Interviewers
                  </Link>
                )}

                <div className="pt-4 border-t flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-500 rounded-2xl flex items-center justify-center text-white text-xl font-semibold">
                      {user.sub?.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <p className="font-semibold">{user.sub}</p>
                      <p className="text-sm text-gray-500">{user.role?.replace('ROLE_', '')}</p>
                    </div>
                  </div>
                  <button onClick={handleLogout} className="text-red-500">
                    <LogOut size={24} />
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
